protected final JsonToken _startDocument(int ch) throws JacksonException
{
    ch &= 0xFF;

    // Very first byte: could be BOM
    if ((ch == 0xEF) && (_minorState != MINOR_ROOT_BOM)) {
        return _finishBOM(1);
    }

    // If not BOM (or we got past it), could be whitespace or comment to skip
    while (ch <= 0x020) {
        if (ch != INT_SPACE) {
            if (ch == INT_LF) {
                ++_currInputRow;
                _currInputRowStart = _inputPtr;
            } else if (ch == INT_CR) {
                ++_currInputRowAlt;
                _currInputRowStart = _inputPtr;
            } else if (ch != INT_TAB) {
                _reportInvalidSpace(ch);
            }
        }
        if (_inputPtr >= _inputEnd) {
            _minorState = MINOR_ROOT_GOT_SEPARATOR;
            if (_closed) {
                return null;
