package tools.jackson.core.json.async;

import tools.jackson.core.JacksonException;
import tools.jackson.core.JsonToken;
import tools.jackson.core.json.JsonReadFeature;
import tools.jackson.core.util.VersionUtil;

/**
 * Helper class for {@link NonBlockingUtf8JsonParserBase} to encapsulate
 * non-blocking comment and whitespace skipping logic.
 * This class is package-private and has direct access to the parser's
 * protected members for state manipulation and delegation.
 */
class NonBlockingCommentSkipper {
    protected final NonBlockingUtf8JsonParserBase _parser;

    // Constants from NonBlockingJsonParserBase
    private final static int INT_SPACE = NonBlockingJsonParserBase.INT_SPACE;
    private final static int INT_LF = NonBlockingJsonParserBase.INT_LF;
    private final static int INT_CR = NonBlockingJsonParserBase.INT_CR;
    private final static int INT_TAB = NonBlockingJsonParserBase.INT_TAB;
    private final static int INT_SLASH = NonBlockingJsonParserBase.INT_SLASH;
    private final static int INT_ASTERISK = NonBlockingJsonParserBase.INT_ASTERISK;
    private final static int INT_HASH = NonBlockingJsonParserBase.INT_HASH;

    // Feature masks from JsonReadFeature
    private final static int FEAT_MASK_ALLOW_JAVA_COMMENTS = JsonReadFeature.ALLOW_JAVA_COMMENTS.getMask();
    private final static int FEAT_MASK_ALLOW_YAML_COMMENTS = JsonReadFeature.ALLOW_YAML_COMMENTS.getMask();

    // Minor states from NonBlockingJsonParserBase
    private final static int MINOR_COMMENT_LEADING_SLASH = NonBlockingJsonParserBase.MINOR_COMMENT_LEADING_SLASH;
    private final static int MINOR_COMMENT_CLOSING_ASTERISK = NonBlockingJsonParserBase.MINOR_COMMENT_CLOSING_ASTERISK;
    private final static int MINOR_COMMENT_C = NonBlockingJsonParserBase.MINOR_COMMENT_C;
    private final static int MINOR_COMMENT_CPP = NonBlockingJsonParserBase.MINOR_COMMENT_CPP;
    private final static int MINOR_COMMENT_YAML = NonBlockingJsonParserBase.MINOR_COMMENT_YAML;

    private final static int MINOR_PROPERTY_LEADING_WS = NonBlockingJsonParserBase.MINOR_PROPERTY_LEADING_WS;
    private final static int MINOR_PROPERTY_LEADING_COMMA = NonBlockingJsonParserBase.MINOR_PROPERTY_LEADING_COMMA;
    private final static int MINOR_VALUE_LEADING_WS = NonBlockingJsonParserBase.MINOR_VALUE_LEADING_WS;
    private final static int MINOR_VALUE_EXPECTING_COMMA = NonBlockingJsonParserBase.MINOR_VALUE_EXPECTING_COMMA;
    private final static int MINOR_VALUE_EXPECTING_COLON = NonBlockingJsonParserBase.MINOR_VALUE_EXPECTING_COLON;
    private final static int MINOR_VALUE_WS_AFTER_COMMA = NonBlockingJsonParserBase.MINOR_VALUE_WS_AFTER_COMMA;


    public NonBlockingCommentSkipper(NonBlockingUtf8JsonParserBase parser) {
        this._parser = parser;
    }

    public final int skipWS(int ch) throws JacksonException {
        do {
            if (ch != INT_SPACE) {
                if (ch == INT_LF) {
                    _parser._currInputRow++;
                    _parser._currInputRowStart = _parser._inputPtr;
                } else if (ch == INT_CR) {
                    _parser._currInputRowAlt++;
                    _parser._currInputRowStart = _parser._inputPtr;
                } else if (ch != INT_TAB && !_parser._isAllowedCtrlCharRS(ch)) {
                    _parser._reportInvalidSpace(ch);
                }
            }
            if (_parser._inputPtr >= _parser._inputEnd) {
                _parser._updateTokenToNA();
                return 0;
            }
            ch = _parser.getNextUnsignedByteFromBuffer();
        } while (ch <= INT_SPACE);
        return ch;
    }

    public final JsonToken startSlashComment(int fromMinorState) throws JacksonException {
        if ((_parser._formatReadFeatures & FEAT_MASK_ALLOW_JAVA_COMMENTS) == 0) {
            _parser._reportUnexpectedChar('/', "maybe a (non-standard) comment? (not recognized as one since Feature 'ALLOW_COMMENTS' not enabled for parser)");
        }

        if (_parser._inputPtr >= _parser._getInputEnd()) {
            _parser._pending32 = fromMinorState;
            _parser._minorState = MINOR_COMMENT_LEADING_SLASH;
            return _parser._updateTokenToNA();
        }
        int ch = _parser.getNextSignedByteFromBuffer();
        if (ch == INT_ASTERISK) { // c-style
            return finishCComment(fromMinorState, false);
        }
        if (ch == INT_SLASH) { // c++-style
            return finishCppComment(fromMinorState);
        }
        _parser._reportUnexpectedChar(ch & 0xFF, "was expecting either '*' or '/' for a comment");
        return null;
    }

    public final JsonToken finishHashComment(int fromMinorState) throws JacksonException {
        if ((_parser._formatReadFeatures & FEAT_MASK_ALLOW_YAML_COMMENTS) == 0) {
            _parser._reportUnexpectedChar('#', "maybe a (non-standard) comment? (not recognized as one since Feature 'ALLOW_YAML_COMMENTS' not enabled for parser)");
        }
        while (true) {
            if (_parser._inputPtr >= _parser._getInputEnd()) {
                _parser._minorState = MINOR_COMMENT_YAML;
                _parser._pending32 = fromMinorState;
                return _parser._updateTokenToNA();
            }
            int ch = _parser.getNextUnsignedByteFromBuffer();
            if (ch < INT_SPACE) {
                if (ch == INT_LF) {
                    _parser._currInputRow++;
                    _parser._currInputRowStart = _parser._inputPtr;
                    break;
                } else if (ch == INT_CR) {
                    _parser._currInputRowAlt++;
                    _parser._currInputRowStart = _parser._inputPtr;
                    break;
                } else if (ch != INT_TAB) {
                    _parser._reportInvalidSpace(ch);
                }
            }
        }
        return startAfterComment(fromMinorState);
    }

    public final JsonToken finishCppComment(int fromMinorState) throws JacksonException {
        while (true) {
            if (_parser._inputPtr >= _parser._getInputEnd()) {
                _parser._minorState = MINOR_COMMENT_CPP;
                _parser._pending32 = fromMinorState;
                return _parser._updateTokenToNA();
            }
            int ch = _parser.getNextUnsignedByteFromBuffer();
            if (ch < INT_SPACE) {
                if (ch == INT_LF) {
                    _parser._currInputRow++;
                    _parser._currInputRowStart = _parser._inputPtr;
                    break;
                } else if (ch == INT_CR) {
                    _parser._currInputRowAlt++;
                    _parser._currInputRowStart = _parser._inputPtr;
                    break;
                } else if (ch != INT_TAB) {
                    _parser._reportInvalidSpace(ch);
                }
            }
        }
        return startAfterComment(fromMinorState);
    }

    public final JsonToken finishCComment(int fromMinorState, boolean gotStar) throws JacksonException {
        while (true) {
            if (_parser._inputPtr >= _parser._getInputEnd()) {
                _parser._minorState = gotStar ? MINOR_COMMENT_CLOSING_ASTERISK : MINOR_COMMENT_C;
                _parser._pending32 = fromMinorState;
                return _parser._updateTokenToNA();
            }
            int ch = _parser.getNextUnsignedByteFromBuffer();
            if (ch < INT_SPACE) {
                if (ch == INT_LF) {
                    _parser._currInputRow++;
                    _parser._currInputRowStart = _parser._inputPtr;
                } else if (ch == INT_CR) {
                    _parser._currInputRowAlt++;
                    _parser._currInputRowStart = _parser._inputPtr;
                } else if (ch != INT_TAB) {
                    _parser._reportInvalidSpace(ch);
                }
            } else if (ch == INT_ASTERISK) {
                gotStar = true;
                continue;
            } else if (ch == INT_SLASH) {
                if (gotStar) {
                    break;
                }
            }
            gotStar = false;
        }
        return startAfterComment(fromMinorState);
    }

    public final JsonToken startAfterComment(int fromMinorState) throws JacksonException {
        if (_parser._inputPtr >= _parser._getInputEnd()) {
            _parser._minorState = fromMinorState;
            return _parser._updateTokenToNA();
